package main

import (
	"context"
	"fmt"
	"io"
	"log"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"

	pb "github.com/example/grpc-auth/proto"
)

const (
	address      = "localhost:50051"
	authTokenKey = "x-auth-token"
	validAuthToken = "super-secret-token"
	invalidAuthToken = "wrong-token"
)

func callAuthenticatedUnary(client pb.AuthServiceClient, ctx context.Context, message string, token string) {
	fmt.Printf("\n--- Client: Calling AuthenticatedCall (Unary) with token: '%s' ---\n", token)

	// Create a context with outgoing metadata for the authentication token
	md := metadata.Pairs(authTokenKey, token)
	authCtx := metadata.NewOutgoingContext(ctx, md)

	req := &pb.AuthRequest{Message: message}
	resp, err := client.AuthenticatedCall(authCtx, req)

	if err != nil {
		st, ok := status.FromError(err)
		if ok && st.Code() == codes.Unauthenticated {
			log.Printf("Client ERROR: Authentication failed: %v", st.Message())
		} else {
			log.Printf("Client ERROR: Could not call AuthenticatedCall: %v", err)
		}
		return
	}

	log.Printf("Client SUCCESS: Server response: %s", resp.GetReply())
}

func callAuthenticatedStream(client pb.AuthServiceClient, ctx context.Context, message string, token string) {
	fmt.Printf("\n--- Client: Calling StreamAuthenticatedCall (Stream) with token: '%s' ---\n", token)

	md := metadata.Pairs(authTokenKey, token)
	authCtx := metadata.NewOutgoingContext(ctx, md)

	req := &pb.AuthRequest{Message: message}
	stream, err := client.StreamAuthenticatedCall(authCtx, req)
	if err != nil {
		st, ok := status.FromError(err)
		if ok && st.Code() == codes.Unauthenticated {
			log.Printf("Client ERROR: Authentication failed for stream: %v", st.Message())
		} else {
			log.Printf("Client ERROR: Could not call StreamAuthenticatedCall: %v", err)
		}
		return
	}

	for {
		resp, err := stream.Recv()
		if err == io.EOF {
			log.Println("Client: Stream finished.")
			break
		}
		if err != nil {
			log.Printf("Client ERROR: Failed to receive stream response: %v", err)
			break
		}
		log.Printf("Client SUCCESS: Stream response: %s", resp.GetReply())
	}
}

func main() {
	// Set up a connection to the server.
	conn, err := grpc.Dial(address, grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		log.Fatalf("Client: did not connect: %v", err)
	}
	defer conn.Close()
	c := pb.NewAuthServiceClient(conn)

	// Contact the server and print out its response.
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	// --- Test Cases ---

	// 1. Unary call with valid token
	callAuthenticatedUnary(c, ctx, "Hello, server! This is an authenticated unary call.", validAuthToken)
	time.Sleep(100 * time.Millisecond) // Give time for logs

	// 2. Unary call with invalid token
	callAuthenticatedUnary(c, ctx, "Who are you? (Invalid token)", invalidAuthToken)
	time.Sleep(100 * time.Millisecond)

	// 3. Unary call with missing token
	callAuthenticatedUnary(c, ctx, "Where is my token? (Missing token)", "")
	time.Sleep(100 * time.Millisecond)

	// 4. Stream call with valid token
	callAuthenticatedStream(c, ctx, "Stream me something! (Authenticated stream)", validAuthToken)
	time.Sleep(100 * time.Millisecond)

	// 5. Stream call with invalid token
	callAuthenticatedStream(c, ctx, "Stream for unauthorized! (Invalid token)", invalidAuthToken)
	time.Sleep(100 * time.Millisecond)

	// 6. Stream call with missing token
	callAuthenticatedStream(c, ctx, "Stream without token! (Missing token)", "")
	time.Sleep(100 * time.Millisecond)
}

